SELECT COUNT(1)
  FROM USER_TABLES
 WHERE TABLE_NAME = #{tableName}

SELECT COUNT(1)
  FROM USER_INDEXES
 WHERE INDEX_NAME = #{indexName}

SELECT COUNT(1)
  FROM USER_VIEWS
 WHERE VIEW_NAME = #{viewName}

SELECT UPPER(TABLE_NAME) TABLENAME, COMMENTS TABLEDESC
  FROM USER_TAB_COMMENTS
 WHERE UPPER(TABLE_NAME) = #{tableName}
